#include <stdio.h>

void minCoins(int coins[], int n, int amount) {
  int result[100];
  int count = 0;
  for (int i = n - 1; i >= 0; i--) {
    while (amount >= coins[i]) {
      amount -= coins[i];
      result[count++] = coins[i];
    }
  }
  printf("Minimum currency units needed: ");
  for (int i = 0; i < count; i++) {
    printf("%d ", result[i]);
  }
  printf("\n");
}

int main() {
  int coins[] = {1, 5, 10, 25};
  int n = 4;
  int amount = 48;
  minCoins(coins, n, amount);
  return 0;
}
// Output: Minimum currency units needed: 25 10 10 1 1 1

