#include <iostream>
#include <vector>

void minCoins(std::vector<int>& coins, int amount) {
  std::vector<int> result;
  for (int i = coins.size() - 1; i >= 0; i--) {
    while (amount >= coins[i]) {
      amount -= coins[i];
      result.push_back(coins[i]);
    }
  }
  std::cout << "Minimum currency units needed: ";
  for (int coin : result) {
    std::cout << coin << " ";
  }
  std::cout << std::endl;
}

int main() {
  std::vector<int> coins = {1, 5, 10, 25};
  int amount = 48;
  minCoins(coins, amount);
  return 0;
}
// Output: Minimum currency units needed: 25 10 10 1 1 1

