using System;
using System.Collections.Generic;

class Program {
  static void MinCoins(int[] coins, int amount) {
    List<int> result = new List<int>();
    for (int i = coins.Length - 1; i >= 0; i--) {
      while (amount >= coins[i]) {
        amount -= coins[i];
        result.Add(coins[i]);
      }
    }
    Console.Write("Minimum currency units needed: ");
    foreach (int coin in result) {
      Console.Write(coin + " ");
    }
    Console.WriteLine();
  }

  static void Main() {
    int[] coins = {1, 5, 10, 25};
    int amount = 48;
    MinCoins(coins, amount);
  }
}
// Output: Minimum currency units needed: 25 10 10 1 1 1

